import datetime
import sqlite3
import tempfile
import os

import jwt
import pytest
from werkzeug.security import generate_password_hash

from src.app import create_app

_SECRET = "dev-secret"
_TEST_EMAIL = "test@example.com"
_TEST_PASSWORD = "correct-password"


@pytest.fixture()
def app(tmp_path):
    db_path = str(tmp_path / "test.db")
    conn = sqlite3.connect(db_path)
    conn.execute(
        "CREATE TABLE users (id INTEGER PRIMARY KEY, username TEXT, email TEXT, password_hash TEXT)"
    )
    conn.execute(
        "INSERT INTO users (username, email, password_hash) VALUES (?, ?, ?)",
        ("testuser", _TEST_EMAIL, generate_password_hash(_TEST_PASSWORD)),
    )
    conn.commit()
    conn.close()

    # Patch User to use the test DB
    import src.models.user as user_module
    original_init = user_module.User.__init__

    def patched_init(self, db_path=db_path):
        original_init(self, db_path)

    user_module.User.__init__ = patched_init

    flask_app = create_app()
    flask_app.config["TESTING"] = True

    yield flask_app

    user_module.User.__init__ = original_init


@pytest.fixture()
def client(app):
    return app.test_client()


def _make_token(payload_override=None, secret=_SECRET):
    payload = {
        "user_id": 1,
        "email": _TEST_EMAIL,
        "exp": datetime.datetime.utcnow() + datetime.timedelta(hours=1),
    }
    if payload_override:
        payload.update(payload_override)
    return jwt.encode(payload, secret, algorithm="HS256")


# --- login endpoint ---

def test_login_valid_credentials_returns_token(client):
    resp = client.post(
        "/auth/login",
        json={"email": _TEST_EMAIL, "password": _TEST_PASSWORD},
    )
    assert resp.status_code == 200
    data = resp.get_json()
    assert "token" in data
    decoded = jwt.decode(data["token"], _SECRET, algorithms=["HS256"])
    assert decoded["email"] == _TEST_EMAIL


def test_login_wrong_password_returns_401(client):
    resp = client.post(
        "/auth/login",
        json={"email": _TEST_EMAIL, "password": "wrong-password"},
    )
    assert resp.status_code == 401
    assert resp.get_json()["error"] == "invalid credentials"


def test_login_unknown_email_returns_401(client):
