def _make_token(payload_override=None, secret=_SECRET):
    payload = {
        "user_id": 1,
        "email": _TEST_EMAIL,
        "exp": datetime.datetime.utcnow() + datetime.timedelta(hours=1),
    }
    if payload_override:
        payload.update(payload_override)
    return jwt.encode(payload, secret, algorithm="HS256")


